111	// ─── table.insert ─────────────────────────────────────────────────────────────
112	
113	/// C: `tinsert(L)` — implements `table.insert(t [, pos,] v)`.
114	///
115	/// ```c
116	/// static int tinsert (lua_State *L) {
117	///   lua_Integer pos;
118	///   lua_Integer e = aux_getn(L, 1, TAB_RW);
119	///   e = luaL_intop(+, e, 1);
120	///   switch (lua_gettop(L)) {
121	///     case 2: { pos = e; break; }
122	///     case 3: {
123	///       lua_Integer i;
124	///       pos = luaL_checkinteger(L, 2);
125	///       luaL_argcheck(L, (lua_Unsigned)pos - 1u < (lua_Unsigned)e, 2,
126	///                        "position out of bounds");
127	///       for (i = e; i > pos; i--) {
128	///         lua_geti(L, 1, i - 1);
129	///         lua_seti(L, 1, i);
130	///       }
131	///       break;
132	///     }
133	///     default:
134	///       return luaL_error(L, "wrong number of arguments to 'insert'");
135	///   }
136	///   lua_seti(L, 1, pos);
137	///   return 0;
138	/// }
139	/// ```
140	pub fn insert(state: &mut LuaState) -> Result<usize, LuaError> {
141	    let mut e = aux_getn(state, 1, TAB_RW)?;
142	    // C: luaL_intop(+, e, 1) — wrapping unsigned add then re-interpret as signed
143	    e = (e as u64).wrapping_add(1) as i64;
144	
145	    let pos: i64 = match state.get_top() {
146	        // C: case 2 — insert new element at the end
147	        2 => e,
148	        // C: case 3 — explicit position argument
149	        3 => {
150	            let pos = state.check_arg_integer(2)?;
151	            // C: luaL_argcheck(L, (lua_Unsigned)pos - 1u < (lua_Unsigned)e, 2, ...)
152	            // Checks 1 <= pos <= e (wrapping subtraction catches pos <= 0)
153	            if !((pos as u64).wrapping_sub(1) < (e as u64)) {
154	                return Err(LuaError::arg_error(2, "position out of bounds"));
155	            }
156	            // C: for (i = e; i > pos; i--) { lua_geti(L, 1, i-1); lua_seti(L, 1, i); }
157	            let mut i = e;
158	            while i > pos {
159	                // TODO(port): state.table_get_i(stack_pos, integer_key) → lua_geti; verify name
160	                state.table_get_i(1, i - 1)?;
161	                // TODO(port): state.table_set_i(stack_pos, integer_key) → lua_seti (pops top); verify name
162	                state.table_set_i(1, i)?;
163	                i -= 1;
164	            }
165	            pos
166	        }
167	        _ => {
168	            return Err(LuaError::runtime(format_args!(
169	                "wrong number of arguments to 'insert'"
170	            )));
171	        }
172	    };
173	    // C: lua_seti(L, 1, pos) — pops new value and sets table[pos]
174	    state.table_set_i(1, pos)?;
175	    Ok(0)
176	}
