178	// ─── table.remove ─────────────────────────────────────────────────────────────
179	
180	/// C: `tremove(L)` — implements `table.remove(t [, pos])`.
181	///
182	/// ```c
183	/// static int tremove (lua_State *L) {
184	///   lua_Integer size = aux_getn(L, 1, TAB_RW);
185	///   lua_Integer pos = luaL_optinteger(L, 2, size);
186	///   if (pos != size)
187	///     luaL_argcheck(L, (lua_Unsigned)pos - 1u <= (lua_Unsigned)size, 2,
188	///                      "position out of bounds");
189	///   lua_geti(L, 1, pos);
190	///   for ( ; pos < size; pos++) {
191	///     lua_geti(L, 1, pos + 1);
192	///     lua_seti(L, 1, pos);
193	///   }
194	///   lua_pushnil(L);
195	///   lua_seti(L, 1, pos);
196	///   return 1;
197	/// }
198	/// ```
199	pub fn remove(state: &mut LuaState) -> Result<usize, LuaError> {
200	    let size = aux_getn(state, 1, TAB_RW)?;
201	    // TODO(port): state.opt_arg_integer(n, default) → luaL_optinteger; verify method name
202	    let mut pos = state.opt_arg_integer(2, size)?;
203	    if pos != size {
204	        // C: luaL_argcheck — checks 1 <= pos <= size+1
205	        if !((pos as u64).wrapping_sub(1) <= (size as u64)) {
206	            return Err(LuaError::arg_error(2, "position out of bounds"));
207	        }
208	    }
209	    state.table_get_i(1, pos)?;   // push element to be returned
210	    while pos < size {
211	        state.table_get_i(1, pos + 1)?;
212	        state.table_set_i(1, pos)?;
213	        pos += 1;
214	    }
215	    state.push(LuaValue::Nil);
216	    state.table_set_i(1, pos)?;   // remove last slot (table[pos] = nil)
217	    Ok(1)
218	}
