297	// ─── table.concat ─────────────────────────────────────────────────────────────
298	
299	/// C: `addfield(L, b, i)` — push `table[i]` onto the stack, validate it is
300	/// a string-or-number, add its string representation to `buf`, then pop it.
301	///
302	/// ```c
303	/// static void addfield (lua_State *L, luaL_Buffer *b, lua_Integer i) {
304	///   lua_geti(L, 1, i);
305	///   if (l_unlikely(!lua_isstring(L, -1)))
306	///     luaL_error(L, "invalid value (%s) at index %I in table for 'concat'",
307	///                   luaL_typename(L, -1), (LUAI_UACINT)i);
308	///   luaL_addvalue(b);
309	/// }
310	/// ```
311	///
312	/// PORT NOTE: `luaL_Buffer` in C accumulates bytes and then pushes the result;
313	/// Rust uses a `Vec<u8>` accumulator passed by mutable reference instead.
314	fn add_field(state: &mut LuaState, buf: &mut Vec<u8>, idx: i64) -> Result<(), LuaError> {
315	    state.table_get_i(1, idx)?;
316	    // C: lua_isstring — true for LUA_TSTRING and LUA_TNUMBER (numbers coerce to strings)
317	    if !matches!(state.type_at(-1), LuaType::String | LuaType::Number) {
318	        // TODO(port): state.type_name_str_at(-1) returns &'static str for the base type name
319	        let type_name = state.type_name_str_at(-1);
320	        return Err(LuaError::runtime(format_args!(
321	            "invalid value ({:?}) at index {} in table for 'concat'",
322	            type_name, idx
323	        )));
324	    }
325	    // C: luaL_addvalue(b) — convert top to string bytes, append, then pop
326	    // TODO(port): state.to_bytes_at(-1) converts via Lua's tostring coercion; verify method name
327	    let bytes = state.to_bytes_at(-1).ok_or_else(|| LuaError::runtime(format_args!("invalid value at index {}", idx)))?;
328	    buf.extend_from_slice(&bytes);
329	    state.pop_n(1);
330	    Ok(())
331	}
332	
333	/// C: `tconcat(L)` — implements `table.concat(t [, sep [, i [, j]]])`.
334	///
335	/// ```c
336	/// static int tconcat (lua_State *L) {
337	///   luaL_Buffer b;
338	///   lua_Integer last = aux_getn(L, 1, TAB_R);
339	///   size_t lsep;
340	///   const char *sep = luaL_optlstring(L, 2, "", &lsep);
341	///   lua_Integer i = luaL_optinteger(L, 3, 1);
342	///   last = luaL_optinteger(L, 4, last);
343	///   luaL_buffinit(L, &b);
344	///   for (; i < last; i++) { addfield(L, &b, i); luaL_addlstring(&b, sep, lsep); }
345	///   if (i == last) addfield(L, &b, i);
346	///   luaL_pushresult(&b);
347	///   return 1;
348	/// }
349	/// ```
350	pub fn concat(state: &mut LuaState) -> Result<usize, LuaError> {
351	    let last = aux_getn(state, 1, TAB_R)?;
352	    // TODO(port): state.opt_arg_lstring(n, default) → luaL_optlstring; verify method name
353	    // Clone the separator before any stack-mutating calls that might invalidate it.
354	    let sep: Vec<u8> = state.opt_arg_lstring(2, Some(b""))?.unwrap_or_default();
355	    let mut i = state.opt_arg_integer(3, 1)?;
356	    let last = state.opt_arg_integer(4, last)?;
357	
358	    // PORT NOTE: C uses luaL_Buffer (which may back-patch the stack);
359	    // Rust uses a plain Vec<u8> accumulator and pushes the result at the end.
360	    let mut buf: Vec<u8> = Vec::new();
361	    while i < last {
362	        add_field(state, &mut buf, i)?;
363	        buf.extend_from_slice(&sep);
364	        i += 1;
365	    }
366	    if i == last {
367	        add_field(state, &mut buf, i)?;
368	    }
369	    // C: luaL_pushresult(&b) — push accumulated string
370	    // TODO(port): state.push_lstring pushes a Lua string from &[u8]; verify method name
371	    state.push_lstring(&buf)?;
372	    Ok(1)
373	}
