375	// ─── table.pack / table.unpack ────────────────────────────────────────────────
376	
377	/// C: `tpack(L)` — implements `table.pack(...)`.
378	///
379	/// Creates a new table `t` with all arguments as integer keys and `t.n` set
380	/// to the argument count.
381	///
382	/// ```c
383	/// static int tpack (lua_State *L) {
384	///   int i;
385	///   int n = lua_gettop(L);
386	///   lua_createtable(L, n, 1);
387	///   lua_insert(L, 1);
388	///   for (i = n; i >= 1; i--)
389	///     lua_seti(L, 1, i);
390	///   lua_pushinteger(L, n);
391	///   lua_setfield(L, 1, "n");
392	///   return 1;
393	/// }
394	/// ```
395	pub fn pack(state: &mut LuaState) -> Result<usize, LuaError> {
396	    let n = state.get_top();
397	    // TODO(port): state.create_table(narr, nrec) → lua_createtable; verify method name
398	    state.create_table(n, 1)?;
399	    // C: lua_insert(L, 1) — move the new table to position 1, shifting args up
400	    state.insert(1);
401	    // C: for (i = n; i >= 1; i--) lua_seti(L, 1, i)
402	    // table_set_i pops the top; args shift from n+1..=2 down to 1..=n as we pop
403	    for i in (1..=n).rev() {
404	        state.table_set_i(1, i as i64)?;
405	    }
406	    state.push(LuaValue::Int(n as i64));
407	    // TODO(port): state.set_field(stack_pos, key_bytes) → lua_setfield; verify method name
408	    state.set_field(1, b"n")?;
409	    Ok(1)
410	}
