412	/// C: `tunpack(L)` — implements `table.unpack(t [, i [, j]])`.
413	///
414	/// Pushes `t[i], t[i+1], …, t[j]` and returns the count.
415	///
416	/// ```c
417	/// static int tunpack (lua_State *L) {
418	///   lua_Unsigned n;
419	///   lua_Integer i = luaL_optinteger(L, 2, 1);
420	///   lua_Integer e = luaL_opt(L, luaL_checkinteger, 3, luaL_len(L, 1));
421	///   if (i > e) return 0;
422	///   n = (lua_Unsigned)e - i;
423	///   if (l_unlikely(n >= (unsigned int)INT_MAX ||
424	///                  !lua_checkstack(L, (int)(++n))))
425	///     return luaL_error(L, "too many results to unpack");
426	///   for (; i < e; i++) lua_geti(L, 1, i);
427	///   lua_geti(L, 1, e);
428	///   return (int)n;
429	/// }
430	/// ```
431	pub fn unpack(state: &mut LuaState) -> Result<usize, LuaError> {
432	    let i = state.opt_arg_integer(2, 1)?;
433	    // C: luaL_opt(L, luaL_checkinteger, 3, luaL_len(L, 1))
434	    let e = if matches!(state.type_at(3), LuaType::None | LuaType::Nil) {
435	        state.length_at(1)?
436	    } else {
437	        state.check_arg_integer(3)?
438	    };
439	    if i > e {
440	        return Ok(0); // empty range
441	    }
442	    // C: n = (lua_Unsigned)e - i  — unsigned subtraction avoids overflow at extremes
443	    let n = (e as u64).wrapping_sub(i as u64);
444	    // C: n >= (unsigned int)INT_MAX || !lua_checkstack(L, (int)(++n))
445	    // The size check uses the pre-increment value so that a wrapped-to-0 result
446	    // (e.g. i=minI, e=maxI yields n = 2^64-1 pre-inc, 0 post-inc) still trips
447	    // the error rather than silently entering a 2^64-iteration loop.
448	    if n >= i32::MAX as u64 {
449	        return Err(LuaError::runtime(format_args!("too many results to unpack")));
450	    }
451	    let n = n + 1;
452	    if !state.check_stack_growth(n as i32) {
453	        return Err(LuaError::runtime(format_args!("too many results to unpack")));
454	    }
455	    let n = n as i64;
456	    let mut k = i;
457	    while k < e {
458	        state.table_get_i(1, k)?;
459	        k += 1;
460	    }
461	    state.table_get_i(1, e)?; // push last element
462	    Ok(n as usize)
463	}
