465	// ─── Quicksort ────────────────────────────────────────────────────────────────
466	
467	/// C: `l_randomizePivot()` — produce a "random" `u32` to randomize pivot
468	/// selection when a partition is severely imbalanced.
469	///
470	/// C: uses `clock()` and `time()` as entropy sources via `memcpy` into a
471	/// `unsigned int` array whose elements are summed.
472	///
473	/// PORT NOTE: Rust uses `SystemTime` as an entropy source instead of
474	/// POSIX `clock()`/`time()`. The mixing is simplified (subsecond nanos XOR-
475	/// shifted) but serves the same purpose: breaking pathological patterns.
476	fn randomize_pivot() -> u32 {
477	    use std::time::{SystemTime, UNIX_EPOCH};
478	    let nanos = SystemTime::now()
479	        .duration_since(UNIX_EPOCH)
480	        .map(|d| d.subsec_nanos())
481	        .unwrap_or(0u32);
482	    nanos ^ nanos.wrapping_shr(16)
483	}
484	
485	/// C: `set2(L, i, j)` — pop the top two stack values and assign them to
486	/// `table[i]` and `table[j]` respectively (table is at stack position 1).
487	///
488	/// ```c
489	/// static void set2 (lua_State *L, IdxT i, IdxT j) {
490	///   lua_seti(L, 1, i);
491	///   lua_seti(L, 1, j);
492	/// }
493	/// ```
494	fn set2(state: &mut LuaState, i: IdxT, j: IdxT) -> Result<(), LuaError> {
495	    // First seti pops the stack top; second seti pops the new top.
496	    state.table_set_i(1, i as i64)?;
497	    state.table_set_i(1, j as i64)?;
498	    Ok(())
499	}
500	
501	/// C: `sort_comp(L, a, b)` — return `true` iff `stack[a] < stack[b]` per the
502	/// sort order: either the `<` operator (if arg 2 is nil) or the user's
503	/// comparison function at stack position 2.
504	///
505	/// ```c
506	/// static int sort_comp (lua_State *L, int a, int b) {
507	///   if (lua_isnil(L, 2))
508	///     return lua_compare(L, a, b, LUA_OPLT);
509	///   else {
510	///     int res;
511	///     lua_pushvalue(L, 2);
512	///     lua_pushvalue(L, a-1);
513	///     lua_pushvalue(L, b-2);
514	///     lua_call(L, 2, 1);
515	///     res = lua_toboolean(L, -1);
516	///     lua_pop(L, 1);
517	///     return res;
518	///   }
519	/// }
520	/// ```
521	///
522	/// The offsets `a-1` and `b-2` compensate for the function and first-argument
523	/// copies pushed before the respective values: `a-1` accounts for the function
524	/// push; `b-2` accounts for both the function push and the copy of `a`.
525	fn sort_comp(state: &mut LuaState, a: i32, b: i32) -> Result<bool, LuaError> {
526	    if state.type_at(2) == LuaType::Nil {
527	        // No user comparator: use the default `<` operator.
528	        return state.compare(a, b, CompareOp::Lt);
529	    }
530	    // User comparator at stack position 2.
531	    state.push_value_at(2);       // push function
532	    state.push_value_at(a - 1);   // push copy of a (compensate for function push)
533	    state.push_value_at(b - 2);   // push copy of b (compensate for function + a copy)
534	    // C: lua_call(L, 2, 1)
535	    state.call(2, 1)?;
536	    // C: res = lua_toboolean(L, -1); lua_pop(L, 1)
537	    // TODO(port): state.to_boolean(-1) → lua_toboolean (never fails); verify method name
538	    let res = state.to_boolean(-1);
539	    state.pop_n(1);
540	    Ok(res)
541	}
542	
543	/// C: `partition(L, lo, up)` — in-place partition around the pivot `P` that
544	/// is already on the top of the Lua stack.
545	///
546	/// Precondition: `a[lo] <= P == a[up-1] <= a[up]` and `P` is at stack top.
547	/// Postcondition: `a[lo..i-1] <= a[i] == P <= a[i+1..up]`; stack is clean.
548	/// Returns the final pivot index `i`.
549	///
550	/// ```c
551	/// static IdxT partition (lua_State *L, IdxT lo, IdxT up) {
552	///   IdxT i = lo;
553	///   IdxT j = up - 1;
554	///   for (;;) {
555	///     while ((void)lua_geti(L, 1, ++i), sort_comp(L, -1, -2)) {
556	///       if (l_unlikely(i == up - 1))
557	///         luaL_error(L, "invalid order function for sorting");
558	///       lua_pop(L, 1);
559	///     }
560	///     while ((void)lua_geti(L, 1, --j), sort_comp(L, -3, -1)) {
561	///       if (l_unlikely(j < i))
562	///         luaL_error(L, "invalid order function for sorting");
563	///       lua_pop(L, 1);
564	///     }
565	///     if (j < i) {
566	///       lua_pop(L, 1);
567	///       set2(L, up - 1, i);
568	///       return i;
569	///     }
570	///     set2(L, i, j);
571	///   }
572	/// }
573	/// ```
574	fn partition(state: &mut LuaState, lo: IdxT, up: IdxT) -> Result<IdxT, LuaError> {
575	    let mut i: IdxT = lo;
576	    let mut j: IdxT = up - 1;
577	    // Entry: stack top is P (pivot value).
578	    loop {
579	        // Advance i: find first a[i] >= P.
580	        // Stack during i-loop body: P(-2), a[i](-1)
581	        loop {
582	            i += 1;
583	            state.table_get_i(1, i as i64)?; // push a[i]
584	            if !sort_comp(state, -1, -2)? {
585	                // a[i] >= P: leave a[i] on stack and exit
586	                break;
587	            }
588	            // a[i] < P; check for invalid comparator
589	            if i == up - 1 {
590	                return Err(LuaError::runtime(format_args!(
591	                    "invalid order function for sorting"
592	                )));
593	            }
594	            state.pop_n(1); // remove a[i]
595	        }
596	        // Retreat j: find last a[j] <= P.
597	        // Stack during j-loop body: P(-3), a[i](-2), a[j](-1)
598	        loop {
599	            // PERF(port): wrapping_sub mirrors C unsigned IdxT behaviour for edge cases
600	            j = j.wrapping_sub(1);
601	            state.table_get_i(1, j as i64)?; // push a[j]
602	            if !sort_comp(state, -3, -1)? {
603	                // P >= a[j]: leave a[j] on stack and exit
604	                break;
605	            }
606	            // P < a[j]; check for invalid comparator
607	            if j < i {
608	                return Err(LuaError::runtime(format_args!(
609	                    "invalid order function for sorting"
610	                )));
611	            }
612	            state.pop_n(1); // remove a[j]
613	        }
614	        // Stack: P(-3), a[i](-2), a[j](-1)
615	        if j < i {
616	            // No out-of-place elements; finalize: place pivot at position i.
617	            state.pop_n(1); // pop a[j]; stack: P(-2), a[i](-1)
618	            set2(state, up - 1, i)?; // table[up-1] = a[i], table[i] = P; stack clean
619	            return Ok(i);
620	        }
621	        // Swap a[i] and a[j] to restore loop invariant.
622	        // set2: table[i] = a[j] (pops -1), table[j] = a[i] (pops new -1); stack: P(-1)
623	        set2(state, i, j)?;
624	    }
625	}
626	
627	/// C: `choosePivot(lo, up, rnd)` — select a pivot index in the middle half of
628	/// `[lo, up]`, randomised by `rnd`.
629	///
630	/// ```c
631	/// static IdxT choosePivot (IdxT lo, IdxT up, unsigned int rnd) {
632	///   IdxT r4 = (up - lo) / 4;
633	///   IdxT p = rnd % (r4 * 2) + (lo + r4);
634	///   lua_assert(lo + r4 <= p && p <= up - r4);
635	///   return p;
636	/// }
637	/// ```
638	fn choose_pivot(lo: IdxT, up: IdxT, rnd: u32) -> IdxT {
639	    let r4 = (up - lo) / 4; // range / 4
640	    let p = rnd % (r4 * 2) + (lo + r4);
641	    debug_assert!(lo + r4 <= p && p <= up - r4);
642	    p
643	}
644	
645	/// C: `auxsort(L, lo, up, rnd)` — recursive quicksort driver.
646	///
647	/// Sorts `table[lo..=up]` in place, recursing on the smaller partition and
648	/// tail-looping on the larger (to bound Rust's call stack). Randomises pivot
649	/// selection when a partition is badly imbalanced.
650	///
651	/// ```c
652	/// static void auxsort (lua_State *L, IdxT lo, IdxT up, unsigned int rnd) {
653	///   while (lo < up) {
654	///     IdxT p, n;
655	///     lua_geti(L, 1, lo); lua_geti(L, 1, up);
656	///     if (sort_comp(L, -1, -2)) set2(L, lo, up); else lua_pop(L, 2);
657	///     if (up - lo == 1) return;
658	///     if (up - lo < RANLIMIT || rnd == 0) p = (lo + up)/2;
659	///     else p = choosePivot(lo, up, rnd);
660	///     lua_geti(L, 1, p); lua_geti(L, 1, lo);
661	///     if (sort_comp(L, -2, -1)) set2(L, p, lo);
662	///     else {
663	///       lua_pop(L, 1); lua_geti(L, 1, up);
664	///       if (sort_comp(L, -1, -2)) set2(L, p, up); else lua_pop(L, 2);
665	///     }
666	///     if (up - lo == 2) return;
667	///     lua_geti(L, 1, p); lua_pushvalue(L, -1); lua_geti(L, 1, up - 1);
668	///     set2(L, p, up - 1);
669	///     p = partition(L, lo, up);
670	///     if (p - lo < up - p) {
671	///       auxsort(L, lo, p - 1, rnd); n = p - lo; lo = p + 1;
672	///     } else {
673	///       auxsort(L, p + 1, up, rnd); n = up - p; up = p - 1;
674	///     }
675	///     if ((up - lo) / 128 > n) rnd = l_randomizePivot();
676	///   }
677	/// }
678	/// ```
679	fn aux_sort(state: &mut LuaState, mut lo: IdxT, mut up: IdxT, mut rnd: u32) -> Result<(), LuaError> {
680	    while lo < up {
681	        // Step 1: ensure a[lo] <= a[up] (cheap two-element sort)
682	        state.table_get_i(1, lo as i64)?; // push a[lo]
683	        state.table_get_i(1, up as i64)?; // push a[up]
684	        // C: if (sort_comp(L, -1, -2)) — a[up] < a[lo]?
685	        if sort_comp(state, -1, -2)? {
686	            set2(state, lo, up)?; // swap so a[lo] <= a[up]
687	        } else {
688	            state.pop_n(2);
689	        }
690	        if up - lo == 1 {
691	            return Ok(()); // only 2 elements, now sorted
692	        }
693	
694	        // Step 2: choose pivot index
695	        let mut p: IdxT = if up - lo < RANLIMIT || rnd == 0 {
696	            (lo + up) / 2 // midpoint pivot for small/non-random runs
697	        } else {
698	            choose_pivot(lo, up, rnd)
699	        };
700	
701	        // Step 3: median-of-three: sort a[lo], a[p], a[up]
702	        state.table_get_i(1, p as i64)?;  // push a[p]
703	        state.table_get_i(1, lo as i64)?; // push a[lo]
704	        // C: if (sort_comp(L, -2, -1)) — a[p] < a[lo]?
705	        if sort_comp(state, -2, -1)? {
706	            set2(state, p, lo)?; // swap a[p] ↔ a[lo]; stack clean
707	        } else {
708	            state.pop_n(1); // remove a[lo]; stack: a[p]
709	            state.table_get_i(1, up as i64)?; // push a[up]; stack: a[p], a[up]
710	            // C: if (sort_comp(L, -1, -2)) — a[up] < a[p]?
711	            if sort_comp(state, -1, -2)? {
712	                set2(state, p, up)?; // swap a[p] ↔ a[up]; stack clean
713	            } else {
714	                state.pop_n(2); // remove a[up] and a[p]; stack clean
715	            }
716	        }
717	        // Stack is clean at this point.
718	        if up - lo == 2 {
719	            return Ok(()); // only 3 elements, now sorted
720	        }
721	
722	        // Step 4: move pivot to a[up-1] and call partition.
723	        //
724	        // Stack evolution:
725	        //   table_get_i(p):    a[p]  (-1)
726	        //   push_value_at(-1): a[p]  (-2), a[p]_copy  (-1)
727	        //   table_get_i(up-1): a[p]  (-3), a[p]_copy  (-2), a[up-1]  (-1)
728	        //   set2(p, up-1):     table[p] = a[up-1], table[up-1] = a[p]_copy;
729	        //                      stack: a[p] (-1)  ← pivot for partition
730	        state.table_get_i(1, p as i64)?;
731	        state.push_value_at(-1); // duplicate: two copies of pivot on stack
732	        state.table_get_i(1, (up - 1) as i64)?;
733	        set2(state, p, up - 1)?;
734	        // One copy of the pivot value remains at the stack top for partition.
735	
736	        p = partition(state, lo, up)?;
737	        // Stack is clean after partition returns.
738	
739	        // Step 5: recurse on smaller partition; tail-loop on larger.
740	        let n: IdxT;
741	        if p - lo < up - p {
742	            aux_sort(state, lo, p - 1, rnd)?;
743	            n = p - lo;
744	            lo = p + 1; // tail: sort [p+1 .. up]
745	        } else {
746	            aux_sort(state, p + 1, up, rnd)?;
747	            n = up - p;
748	            up = p - 1; // tail: sort [lo .. p-1]
749	        }
750	
751	        // Re-randomise if the partition was severely imbalanced.
752	        // C: if ((up - lo) / 128 > n) rnd = l_randomizePivot()
753	        if (up - lo) / 128 > n {
754	            rnd = randomize_pivot();
755	        }
756	    }
757	    Ok(())
758	}
759	
760	/// C: `sort(L)` — implements `table.sort(t [, comp])`.
761	///
762	/// ```c
763	/// static int sort (lua_State *L) {
764	///   lua_Integer n = aux_getn(L, 1, TAB_RW);
765	///   if (n > 1) {
766	///     luaL_argcheck(L, n < INT_MAX, 1, "array too big");
767	///     if (!lua_isnoneornil(L, 2))
768	///       luaL_checktype(L, 2, LUA_TFUNCTION);
769	///     lua_settop(L, 2);
770	///     auxsort(L, 1, (IdxT)n, 0);
771	///   }
772	///   return 0;
773	/// }
774	/// ```
775	pub fn sort(state: &mut LuaState) -> Result<usize, LuaError> {
776	    let n = aux_getn(state, 1, TAB_RW)?;
777	    if n > 1 {
778	        if !(n < i32::MAX as i64) {
779	            return Err(LuaError::arg_error(1, "array too big"));
780	        }
781	        if !matches!(state.type_at(2), LuaType::None | LuaType::Nil) {
782	            state.check_arg_type(2, LuaType::Function)?;
783	        }
784	        // C: lua_settop(L, 2) — discard any extra arguments.
785	        // Must go through the public C-API set_top (relative to the call
786	        // frame); the inherent LuaState::set_top treats its argument as
787	        // an absolute stack slot and would corrupt the frame.
788	        lua_vm::api::set_top(state, 2)?;
789	        aux_sort(state, 1, n as IdxT, 0)?;
790	    }
791	    Ok(0)
792	}
793	
794	// ─── Registration ─────────────────────────────────────────────────────────────
795	
796	/// C: `tab_funcs[]` — the function registration table for `require("table")`.
797	///
798	/// ```c
799	/// static const luaL_Reg tab_funcs[] = {
800	///   {"concat", tconcat}, {"insert", tinsert}, {"pack", tpack},
801	///   {"unpack", tunpack}, {"remove", tremove}, {"move", tmove},
802	///   {"sort", sort}, {NULL, NULL}
803	/// };
804	/// ```
805	///
806	/// PORT NOTE: In Rust we represent this as a slice of `(&[u8], fn-ptr)` pairs;
807	/// the sentinel `{NULL, NULL}` is implicit (the slice has a known length).
808	pub const TABLE_FUNCS: &[(&[u8], fn(&mut LuaState) -> Result<usize, LuaError>)] = &[
809	    (b"concat", concat),
810	    (b"insert", insert),
811	    (b"pack", pack),
812	    (b"unpack", unpack),
813	    (b"remove", remove),
814	    (b"move", tmove),
815	    (b"sort", sort),
816	];
817	
818	// ─── Module opener ────────────────────────────────────────────────────────────
819	
820	/// C: `luaopen_table(L)` — open the `table` library.
821	///
822	/// ```c
823	/// LUAMOD_API int luaopen_table (lua_State *L) {
824	///   luaL_newlib(L, tab_funcs);
825	///   return 1;
826	/// }
827	/// ```
828	pub fn open_table(state: &mut LuaState) -> Result<usize, LuaError> {
829	    // C: LUAMOD_API → pub  (see macros.tsv)
830	    // TODO(port): state.new_lib → luaL_newlib; creates a new table and registers functions;
831	    //             verify method name and signature
832	    state.new_lib(TABLE_FUNCS)?;
833	    Ok(1)
834	}
835	
836	// ──────────────────────────────────────────────────────────────────────────────
837	// PORT STATUS
838	//   source:        src/ltablib.c  (430 lines, 14 functions)
839	//   target_crate:  lua-stdlib
840	//   confidence:    medium
841	//   todos:         18
842	//   port_notes:    5
843	//   unsafe_blocks: 0
844	//   notes:         Logic is faithfully translated. All TODOs are method-name
845	//                  uncertainties for LuaState API calls (table_get_i, table_set_i,
846	//                  opt_arg_integer, opt_arg_lstring, get_metatable, to_bytes_at,
847	//                  push_lstring, push_value_at, compare, new_lib, set_top,
848	//                  check_stack_growth, type_name_str_at, create_table) — Phase B
849	//                  maps these to the real method names once lua-vm is drafted.
850	//                  Stack cleanup on error paths is elided (C uses longjmp);
851	//                  needs Phase B attention in check_tab and add_field.
852	// ──────────────────────────────────────────────────────────────────────────────
853

